                        current_selection = new_selection

        # Final check
        sol = {"selected_columns": sorted(current_selection)}
        is_f, _ = tools['is_feasible'](sol)
        if is_f:
            return sol
    except Exception:
        pass

    # Return the best we could do (even if empty, as per template)
